export interface Question {
  id: string;
  question: string;
  answer: string;
  hints: [string, string, string];
  topicId: string;
  difficulty: 'easy' | 'medium' | 'hard';
  choices?: string[]; // If present, always render as A/B/C/D tap targets
}

export interface SpeedDrill {
  id: string;
  question: string;
  answer: string;
  category: string;
}

export interface Topic {
  id: string;
  name: string;
  emoji: string;
  description: string;
  color: string;
  rank: number;
  questions: Question[];
}

